package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.util.*;import com.hospital.management.validation.*;import org.slf4j.*;import java.sql.*;import java.time.*;import java.util.*;
/** Transactional prescription header/item workflow with medical-record ownership. */public class PrescriptionServiceImpl implements PrescriptionService {private static final Logger LOG=LoggerFactory.getLogger(PrescriptionServiceImpl.class);private final PrescriptionDao rx;private final PrescriptionItemDao items;private final MedicalRecordDao records;private final DoctorDao doctors;private final PatientDao patients;private final PrescriptionValidator validator;private final AuditLogDao audit;public PrescriptionServiceImpl(){this(new PrescriptionDaoImpl(),new PrescriptionItemDaoImpl(),new MedicalRecordDaoImpl(),new DoctorDaoImpl(),new PatientDaoImpl(),new PrescriptionValidator(),new AuditLogDaoImpl());}public PrescriptionServiceImpl(PrescriptionDao r,PrescriptionItemDao i,MedicalRecordDao m,DoctorDao d,PatientDao p,PrescriptionValidator v,AuditLogDao a){rx=r;items=i;records=m;doctors=d;patients=p;validator=v;audit=a;}
public Page<Prescription>listPrescriptions(PageRequest p,Long pi,Long di,Long dep,LocalDate f,LocalDate t,String st,AuthenticatedUser u){PageRequest q=p==null?new PageRequest(1,10,""):p;try{if(u==null)return empty(q);if("DOCTOR".equals(u.getRoleName())){Doctor d=doctor(u);if(d==null)return empty(q);di=d.getDoctorId();}else if("PATIENT".equals(u.getRoleName())){Patient x=patient(u);if(x==null)return empty(q);pi=x.getPatientId();}else if(!"ADMIN".equals(u.getRoleName()))return empty(q);return rx.findAll(q,pi,di,dep,f,t,st);}catch(SQLException e){LOG.error("Prescription listing failed",e);return empty(q);}}public Optional<Prescription>getPrescription(Long id,AuthenticatedUser u){try{return rx.findById(id).filter(p->canView(p,u));}catch(SQLException e){LOG.error("Prescription lookup failed",e);return Optional.empty();}}public Optional<Prescription>getByMedicalRecord(Long id,AuthenticatedUser u){try{return rx.findByMedicalRecordId(id).filter(p->canView(p,u));}catch(SQLException e){return Optional.empty();}}
public ServiceResult<Long>createPrescription(PrescriptionForm f,AuditContext a,AuthenticatedUser u){ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{MedicalRecord m=records.findById(f.getMedicalRecordId()).orElse(null);if(m==null)return failL(ServiceResult.Status.NOT_FOUND,"Medical record not found");if(!canManage(m.getDoctorId(),u)){event("PRESCRIPTION_ACCESS_DENIED",null,a);return failL(ServiceResult.Status.FORBIDDEN,"Prescription access denied");}if(m.getPatientId()==null||m.getDoctorId()==null||m.getAppointmentId()==null){event("PRESCRIPTION_CREATION_BLOCKED",null,a);return failL(ServiceResult.Status.CONFLICT,"Medical record is not linked to a valid appointment");}if(rx.existsByMedicalRecordId(m.getMedicalRecordId()))return failL(ServiceResult.Status.DUPLICATE,"A prescription already exists for this medical record");Prescription p=from(f);p.setPatientId(m.getPatientId());p.setDoctorId(m.getDoctorId());p.setAppointmentId(m.getAppointmentId());p.setMedicalRecordId(m.getMedicalRecordId());p.setPrescriptionDate(LocalDate.now());long id=tx(c->{long x=rx.createPrescription(c,p);for(PrescriptionItem i:p.getItems()){i.setPrescriptionId(x);items.createItem(c,i);}return x;});event("PRESCRIPTION_CREATED",id,a);return ServiceResult.success("Prescription created",id);}catch(SQLException e){LOG.error("Prescription creation failed",e);if(SqlExceptionUtil.isUniqueConstraintViolation(e))return failL(ServiceResult.Status.DUPLICATE,"A prescription already exists for this medical record");return failL(ServiceResult.Status.SYSTEM_ERROR,"Prescription service is temporarily unavailable");}}
public ServiceResult<Void>updatePrescription(PrescriptionForm f,AuditContext a,AuthenticatedUser u){if(f==null||f.getPrescriptionId()==null)return fail(ServiceResult.Status.NOT_FOUND,"Prescription not found");try{Prescription old=rx.findById(f.getPrescriptionId()).orElse(null);if(old==null)return fail(ServiceResult.Status.NOT_FOUND,"Prescription not found");if(!canManage(old.getDoctorId(),u)){event("PRESCRIPTION_ACCESS_DENIED",old.getPrescriptionId(),a);return fail(ServiceResult.Status.FORBIDDEN,"Prescription access denied");}if(!"ACTIVE".equals(old.getStatus()))return fail(ServiceResult.Status.CONFLICT,"Completed or cancelled prescriptions cannot be edited");f.setMedicalRecordId(old.getMedicalRecordId());f.setStatus(old.getStatus());ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());Prescription p=from(f);p.setPrescriptionId(old.getPrescriptionId());tx(c->{rx.updatePrescription(c,p);items.deleteByPrescriptionId(c,p.getPrescriptionId());for(PrescriptionItem i:p.getItems()){i.setPrescriptionId(p.getPrescriptionId());items.createItem(c,i);}return null;});event("PRESCRIPTION_UPDATED",p.getPrescriptionId(),a);return ServiceResult.success("Prescription updated",null);}catch(SQLException e){LOG.error("Prescription update failed",e);return fail(ServiceResult.Status.SYSTEM_ERROR,"Prescription service is temporarily unavailable");}}
public ServiceResult<Void>updatePrescriptionStatus(Long id,String action,AuditContext a,AuthenticatedUser u){try{Prescription p=rx.findById(id).orElse(null);if(p==null)return fail(ServiceResult.Status.NOT_FOUND,"Prescription not found");if(!canManage(p.getDoctorId(),u)){event("PRESCRIPTION_ACCESS_DENIED",id,a);return fail(ServiceResult.Status.FORBIDDEN,"Prescription access denied");}Optional<String>target=PrescriptionStatusTransition.target(p.getStatus(),action);if(target.isEmpty()){event("PRESCRIPTION_STATUS_CHANGE_BLOCKED",id,a);return fail(ServiceResult.Status.CONFLICT,"Invalid prescription status transition");}tx(c->{rx.updateStatus(c,id,target.get());return null;});event("PRESCRIPTION_"+target.get(),id,a);return ServiceResult.success("Prescription status updated",null);}catch(SQLException e){LOG.error("Prescription status update failed",e);return fail(ServiceResult.Status.SYSTEM_ERROR,"Prescription service is temporarily unavailable");}}
private Prescription from(PrescriptionForm f){Prescription p=new Prescription();p.setValidUntil(f.getValidUntil()==null||f.getValidUntil().isBlank()?null:LocalDate.parse(f.getValidUntil()));p.setNotes(trim(f.getNotes()));p.setStatus(f.getStatus()==null||f.getStatus().isBlank()?"ACTIVE":f.getStatus().toUpperCase());List<PrescriptionItem>x=new ArrayList<>();for(PrescriptionItemForm z:f.getItems()){PrescriptionItem i=new PrescriptionItem();i.setMedicineName(trim(z.getMedicineName()));i.setDosage(trim(z.getDosage()));i.setFrequency(trim(z.getFrequency()));i.setDuration(trim(z.getDuration()));i.setRoute(trim(z.getRoute()));i.setInstructions(trim(z.getInstructions()));x.add(i);}p.setItems(x);return p;}private String trim(String s){return s==null?null:s.trim();}private boolean canManage(Long id,AuthenticatedUser u){if(u==null)return false;if("ADMIN".equals(u.getRoleName()))return true;Doctor d="DOCTOR".equals(u.getRoleName())?doctor(u):null;return d!=null&&d.getDoctorId().equals(id);}private boolean canView(Prescription p,AuthenticatedUser u){if(canManage(p.getDoctorId(),u))return true;if(u!=null&&"PATIENT".equals(u.getRoleName())){Patient x=patient(u);return x!=null&&x.getPatientId().equals(p.getPatientId());}return false;}private Doctor doctor(AuthenticatedUser u){try{return doctors.findByUserId(u.getUserId()).orElse(null);}catch(SQLException e){return null;}}private Patient patient(AuthenticatedUser u){try{return patients.findAll(new PageRequest(1,100,u.getUsername()),"ACTIVE").getContent().stream().filter(p->u.getUserId().equals(p.getUserId())).findFirst().orElse(null);}catch(SQLException e){return null;}}
private<T>T tx(Work<T>w)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){boolean old=c.getAutoCommit();c.setAutoCommit(false);try{T v=w.run(c);c.commit();return v;}catch(SQLException|RuntimeException e){c.rollback();throw e;}finally{c.setAutoCommit(old);}}}private interface Work<T>{T run(Connection c)throws SQLException;}private void event(String e,Long id,AuditContext x){try{AuditContext a=x==null?new AuditContext(null,null,null):x;audit.recordEvent(e,a.userId(),"PRESCRIPTION",id,a.ipAddress(),a.userAgent());}catch(RuntimeException z){LOG.warn("Prescription audit failed: {}",e,z);}}private Page<Prescription>empty(PageRequest p){return new Page<>(List.of(),p.getPageNumber(),p.getPageSize(),0);}private ServiceResult<Void>fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Long>failL(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}}
